```class Solution {
public:
    int flipLights(int n, int presses) {
        int seen[1 << 6] = {};
        for (int i = 0; i < (1 << n); ++i) {
            int cnt[2] = {};
            for (int j = 0; j < n; ++j) {
                cnt[(i >> j) & 1]++;
            }
            int state = 0;
            for (int j = 0; j < 6; ++j) {
                state = state * 2 + (cnt[j % 2] % 2);
            }
            seen[state] = 1;
            for (int j = 0; j <= presses; ++j) {
                int x = i;
                if (j >= 1) x ^= (1 << n) - 1;
                if (j >= 2) x ^= (1 << (n / 2)) - 1;
                if (j >= 3) x ^= (1 << ((n + 1) / 2)) - 1;
                if (j >= 4) x ^= (1 << (n / 3)) - 1;
                cnt[0] = cnt[1] = 0;
                for (int k = 0; k < n; ++k) {
                    cnt[(x >> k) & 1]++;
                }
                state = 0;
                for (int k = 0; k < 6; ++k) {
                    state = state * 2 + (cnt[k % 2] % 2);
                }
                seen[state] = 1;
            }
        }
        return accumulate(seen, seen + (1 << 6), 0);
    }
};
